INSERT INTO `soaltpa` (`id_soal`, `soal`, `jawaban`, `id_kategori`) VALUES
(1, '<p>Dalam kehidupan bernegara, Pancasila berperan sebagai...</p>', 'B', 1),
(2, 'Rumusan Pancasila yang resmi terdapat dalam...', 'C', 1),
(3, 'Dalam sumber tata hukum di Indonesia, Pancasila dijadikan sebagai...', 'A', 1),
(4, 'Pancasila bagi bangsa Indonesia merupakan', 'A', 1),
(5, 'Hubungan sosial yang selaras, serasi, seimbang antara individu dan masyarakat dijiwai oleh nilai-nilai Pancasila, yaitu...', 'A', 1),
(6, 'Berdasarkan pengalaman sejarah, Pancasila sebagai dasar negara ternyata tetap tegak walaupun mengalami berbagai cobaan. Adapun kekuatannya terletak pada:', 'B', 1),
(7, 'Pancasila yang benar dan perlu dihayati serta diamalkan adalah Pancasila yang rumusannya tercantum dalam:', 'A', 1),
(8, 'Pangkal tolak penghayatan dan pengamalan Pancasila adalah...', 'C', 1),
(9, 'Beribadah dan menganut suatu agama atau kepercayaan adalah merupakan asasi.', 'A', 1),
(10, 'Secara formal Pancasila disahkan sebagai dasar negara Republik Indonesia pada tanggal', 'D', 1),
(11, 'Pengakuan de jure dari suatu negara terhadap negara yang lain ditandai oleh...', 'B', 2),
(12, 'Dilihat dari segi tujuannya, negara kepolisian bertujuan...', 'B', 2),
(13, 'Ciri Khas negara kesatuan adalah...', 'B', 2),
(14, 'Apabila didasarkan pada ajaran Trias Politika, yang dikenal dengan teori pemisahan kekuasaan negara, maka penetapan APBN menurut UUD 1945 merupakan campur tangan...', 'A', 2),
(15, 'Jika dibandingkan dengan kabinet parlementer kelebihan kabinet presidentil adalah dalam hal...', 'B', 2),
(16, 'Untuk mempertahankan kedaulatan Republik Indonesia pada tanggal 23 Agustus 1945 Presiden Soekarno mengumumkan berdirinya tiga abadan baru, yaitu...', 'A', 3),
(17, 'Setelah indonesia merdeka dan memperoleh pengakuan internasional, ternyata masalah-masalah yang dihadapi belum berakhir, terutama masalah konstitusi. Pada tahun 1950, setelah terbentuk negara kesatuan, UUD Sementara yang digunakan pada hakikatnya merupaka', 'A', 3),
(18, 'Indonesia menjadi negara-negara nonblok karena ingin netral dalam percaturan dua negara adikuasa, Amerika Serikat dan Rusia. Kedua negara itu setelah Perang dunia II terlibad dalam...', 'B', 3),
(19, 'Evokasi', 'A', 4),
(20, 'BAKU', 'B', 4),
(21, 'PROTESIS', 'D', 4),
(22, 'DIKOTOMI', 'A', 4),
(23, 'SINE QUA NON', 'D', 4),
(24, 'KENDALA', 'B', 5),
(25, 'EKSTRINSIK', 'D', 5),
(26, 'PROMINEN', 'C', 5),
(27, 'Deduksi', 'A', 5),
(28, 'IMIGRASI', 'C', 5),
(29, 'SEMINAR : SARJANA', 'D', 6),
(30, 'FIKTIF : FAKTA', 'D', 6),
(31, 'MATA : TELINGA', 'B', 6),
(32, 'UANG : PUNDI-PUNDI', 'C', 6),
(33, 'PEDATI : KUDA - PESAWAT TERBANG : ...', 'B', 6),
(34, '2,20 x 0,75 + 3/5 : 1/8', 'D', 7),
(35, '7,5 : 2,5 - (2/4 x 3/4) = ...', 'D', 7),
(36, '4/5 + 3/5 + 3/8 + 6/8 + 1 <sup> 1/2 </sup> = ...', 'A', 7),
(37, '( <sup> 1/4 </sup> x 164 ) x <sup> 1/2 </sup>', 'A', 7),
(38, '2 <sup> 1/4 </sup> x 7,5 - 7,5 : 1 <sup> 1/2 </sup> = ...', 'D', 7),
(39, '1 + 2 + 3 + 4 + 5 + .................... + 29 =', 'A', 7),
(40, '1 <sup> 2 </sup> + 2 <sup> 2 </sup>  + 3 <sup> 2 </sup>  + 4 <sup> 2 </sup>  + 5 <sup> 2 </sup>  + .................... 9 <sup> 2 </sup>  =', 'B', 7),
(41, 'Jika a = 5 dan b = 2, maka nilai dari a <sup> 2 </sup>  - 3a <sup> 2 </sup> b + 3ab <sup> 2 </sup>  - b <sup> 2 </sup>  =', 'C', 7),
(42, '(882 + 115)<sup> 2 </sup>  =', 'C', 7),
(43, '... 2 5 6 7 10 9 14', 'D', 8),
(44, '42 13 19 49 19 19 56 25 19 ... ...', 'C', 8),
(45, '5 6 7 8 10 11 14 ... ...', 'A', 8),
(46, 'Semua karyawan harus hadir dalam rapat rutin. Sementara office boy adalah karyawan.', 'C', 9),
(47, 'Ketika ayah dan ibu Hermawan menikah, masing-masing telah memiliki seorang anak. Sekarang Hermawan lahir persis setahun setelah perkawinan tersebut, dan memiliki 4 saudara.', 'A', 9),
(48, 'Jika pernyataan \"Semua Dokter adalah laki-laki\" salah, maka :', 'C', 9),
(49, 'Merpati terbang ke utara. Merpati adalah burung.', 'A', 9);
