INSERT INTO `_petunjuk` (`id`, `created_at`, `updated_at`, `petunjuk`) VALUES
(1, '2020-05-03 19:40:51', '2020-05-03 19:40:52', 'Direction: For questions 1-15, choose the one best answer by marking (A), (B), (C), or (D) to each question based on the reading material.'),
(2, '2020-05-03 19:40:51', '2020-05-03 19:40:52', 'Direction: For questions 16-25, choose the one word or phrase that best complete sentence by marking (A), (B), (C) or (D).'),
(3, '2020-05-03 19:40:51', '2020-05-03 19:40:52', 'Direction: For questions 26-35, each sentence has four words or phrases underlined. Choose (A), (B), (C), or (D) in the sentence that should be corrected.'),
(4, '2020-05-03 19:40:51', '2020-05-03 19:40:52', 'Direction: For questions 36-45, each sentence has a word or phrase underlined. Choose the synonym below the sentence by marking (A), (B), (C), or (D).'),
(5, '2020-05-03 19:40:51', '2020-05-03 19:40:52', 'Direction: For questions 46-50, you will hear a short story. The story will be played just one time so you must listen carefully. After that, choose the sentence by marking (A), (B), (C) or (D) which one is closest in meaning to the statement you heard.');
INSERT INTO `_soal_cerita` (`id`, `created_at`, `updated_at`, `cerita`) VALUES
(1, '2020-05-03 19:40:45', '2020-05-03 19:40:46', 'Next year Bob will become a university student. He wants to have a girlfriend when he becomes a university student. Because of his being overweight, however, he is very unconfident. Therefore, he makes some plans to lose his weight. Starting next month, he will go jogging regularly. Then, he will go to a nutritionist to consult about what to consume and what to avoid. Actually he thinks about joining a fitness club, but since he is very shy to meet new people with his body now, he cancels that plan. The most important plan for him is to do what his mother has always suggested. Her suggestion is that Bob should eat only three apples a day and drink much mineral water. These must be done in the first two weeks. His mother assures him of the quick result. This makes Bob very confident in conducting his plan later.'),
(2, '2020-05-16 00:09:14', '2020-05-16 00:09:15', 'In the mailroom of Howard Co. Ltd, there are two kinds of correspondence which are handled by the clerks. The first one is the incoming mail. In handling the incoming mail, the clerks sort, open, and distribute the letters. However, not all letters are opened. Letters marked personal, private, or confidential must be handed over unopened to the addressee. The second one, the outgoing mail, is collected from all the departments in that company. After all the outgoing letters arrive at the mailroom, they are weighed and franked for the correct postage. Then, they are brought to the post office together with registered or recorded letters. Those special letters, however, are handed in separately over the post office counter.'),
(3, '2020-05-16 00:21:36', '2020-05-16 00:21:37', 'Alan Wentworth, six years old, lived near a construction site where a new factory was being built. There were no parks in the neighborhood, so he liked playing there. One day he was playing with his friends when suddenly a pile of bricks fell over and crushed him to death. Alan’s parents blamed the workers of the construction site, the site foreman, and the owner of the factory. They said it wouldn’t have happened if only the workers had bulit a fence and put warning signs. The owner of the factory said, on the other hand, that Alan wouldn’t have died if his parents had taken care of him well.');
INSERT INTO `_soal_listening` (`id_soal`, `created_at`, `updated_at`, `id_petunjuk`, `id_sound`, `soal`, `opsiA`, `opsiB`, `opsiC`, `opsiD`, `key`) VALUES
(1, '2020-05-03 19:40:31', '2020-05-03 19:40:32', '5', '1', 'What is the speaker’s favorite sport?', 'Catching boots', 'Cleaning rivers', 'Boating', 'Fishing', 'Fishing'),
(2, '2020-05-19 06:33:30', '2020-05-19 06:33:31', '5', '1', 'What do some unlucky fishermen catch?', 'A small fish', 'Old boots', 'Nothing', 'A bag', 'Old boots'),
(3, '2020-05-19 06:35:00', '2020-05-19 06:35:01', '5', '1', 'What does the speaker bring home after fishing?', 'Old boots', 'Some fish', 'An empty bag', 'A boat', 'An empty bag'),
(4, '2020-05-19 06:36:23', '2020-05-19 06:36:24', '5', '1', 'Why do the speaker’s friends ask her to give up fishing?', 'Because she gets too many fish.', 'Because they want the old boots.', 'Because fishing is very exciting.', 'Because it is a waste of time.', 'Because it is a waste of time.'),
(5, '2020-05-19 06:38:15', '2020-05-19 06:38:16', '5', '1', 'According to the speaker, what is the interesting thing from fishing?', 'Catching big fish', 'Doing nothing at all', 'Playing on the river', 'Doing good sport', 'Doing nothing at all');
INSERT INTO `_soal_reading` (`id_soal`, `created_at`, `updated_at`, `id_petunjuk`, `id_cerita`, `soal`, `opsiA`, `opsiB`, `opsiC`, `opsiD`, `key`) VALUES
(1, '2020-05-03 19:40:10', '2020-05-03 19:40:11', '1', '1', 'What does the text tell about?', 'Bob’s tactic to lose his weight.', 'Bob’s tactic to gain his weight.', 'Bob’s tactic to finish his studies at the university.', 'Bob’s tactic to join a diet program.', 'Bob’s tactic to lose his weight.'),
(2, '2020-05-03 19:40:10', '2020-05-03 19:40:11', '1', '1', 'According to the text, how is Bob’s physical appearance? He is . . .', 'slim', 'obese', 'obesity', 'slender', 'obese'),
(3, '2020-05-15 23:43:15', '2020-05-15 23:41:36', '1', '1', 'At present Bob………..', 'Doesn’t have any girl friend.', 'Is still looking for a fitness club.', 'Has a girl friend.', 'Has a girl friend who is a university student.', 'Doesn’t have any girl friend.'),
(4, '2020-05-16 00:03:15', '2020-05-16 00:03:17', '1', '1', 'In order to be confident, below are the things Bob is going to do, <u>except</u>', 'He is going to eat an apple everyday.', 'He is going to eat three apples a day.', 'He is going to go jogging everyday.', 'He is going to find a nutritionist.', 'He is going to eat an apple everyday.'),
(5, '2020-05-16 00:06:28', '2020-05-16 00:06:30', '1', '1', 'Who has convinced Bob that he will be slim in the first two weeks?', 'His nutritionist ', 'His mother', 'His fitness instructor', 'His girlfriend', 'His mother'),
(6, '2020-05-16 00:10:11', '2020-05-16 00:10:09', '1', '2', 'What do the clerks do after sorting the incoming mail?', 'They re-write the mail.', 'They mark the mail.', 'They open the mail.', 'They distribute the mail.', 'They open the mail.'),
(7, '2020-05-16 00:12:29', '2020-05-16 00:12:30', '1', '2', 'Below are the kinds of letters which may not be opened, <u>except</u>:', 'Private	', 'Confidential	', 'Personal', ' Registered', ' Registered'),
(8, '2020-05-16 00:14:14', '2020-05-16 00:14:15', '1', '2', 'Where should the outgoing letters be brought after being franked?', 'To the department', 'To the mailroom', 'To the post office', 'To the company', 'To the post office'),
(9, '2020-05-16 00:15:30', '2020-05-16 00:15:31', '1', '2', 'The statements below are correct based on the text, <u>except</u>:', 'The clerks may open all the incoming letters.', 'Private letters may not be opened by the clerks.', 'Outgoing mail is collected from all the departments.', 'Outgoing letters are weighed and franked.', 'The clerks may open all the incoming letters.'),
(10, '2020-05-16 00:17:15', '2020-05-16 00:17:17', '1', '2', 'The word “they” in the sentence “they are weighed and franked ....” refers to:', 'The clerks', 'Recorded letters', 'Incoming letters', 'Outgoing letters', 'Outgoing letters'),
(11, '2020-05-16 00:21:51', '2020-05-16 00:21:52', '1', '3', 'Based on the text, here are some causes of Alan’s death, except:', 'A pile of bricks fell over and crushed him.', 'He lived far away from the construction site.', 'No fence and signs were bulit at the construction site.', 'His parents didn’t take care of him well.', 'He lived far away from the construction site.'),
(12, '2020-05-16 00:37:42', '2020-05-16 00:37:43', '1', '3', 'What does “park” mean?', 'Playground	', ' Field	', 'Ground', 'Parking lot', 'Playground	'),
(13, '2020-05-16 00:39:15', '2020-05-16 00:39:16', '1', '3', 'What does the word “it” in the sentence “They said <u>it </u>wouldn’t have ....” refer to?', 'The construction site	', 'Alan’s death	', 'The factory	', 'A pile of bricks', 'Alan’s death	'),
(14, '2020-05-16 00:40:52', '2020-05-16 00:40:53', '1', '3', 'Who didn’t Alan’s parents blame for Alan’s death?', 'The site foreman', 'The workers 	', 'The factory owner', 'The government', ' The government'),
(15, '2020-05-16 00:43:36', '2020-05-16 00:43:37', '1', '3', 'What is the main idea of that text?', 'The construction site workers’ carelessness', 'The negligence of Alan’s parents', 'The causes of Alan’s death', 'The unavailability of children’s park', 'The causes of Alan’s death');
