(5, '2020-05-19 06:26:07', '2020-05-19 06:26:09', '4', 'Because of the inheritance, that young lady became the <u>wealthiest</u> person in that village', 'most famous', 'most respected', 'richest', 'prettiest ', 'richest'),
(6, '2020-05-19 06:28:08', '2020-05-19 06:28:08', '4', 'When did you <u>receive</u> the news?', 'accept', 'send', 'give', 'report', 'accept'),
(7, '2020-05-19 06:28:57', '2020-05-19 06:28:58', '4', 'People cannot <u>put up with</u> very loud noise.', 'tolerate', 'minimize', 'maximize', 'adapt', 'tolerate'),
(8, '2020-05-19 06:30:24', '2020-05-19 06:30:25', '4', 'Because of being alone, Mrs. Smith enjoys very much if salesmen <u>call on</u> her.', 'phone', 'invite', 'offer ', 'visit', 'visit'),
