(11, '2020-05-19 05:34:53', '2020-05-19 05:34:57', '3', 'I <u>doesn’t</u> understand <u>what</u> you <u>are talking</u> about <u>with</u> that girl.', 'doesn’t', 'what', 'are talking', 'with', 'doesn’t'),
(12, '2020-05-19 05:35:50', '2020-05-19 05:35:50', '3', 'I <u>didn’t</u> go to class <u>yesterday</u> because <u>I am</u> visited my grandpa <u>in the</u> village.', 'didn’t', 'yesterday', 'I am', 'in the', 'i am'),
