(14, '2020-05-19 05:37:29', '2020-05-19 05:37:30', '3', 'Donnie <u>is gone</u> to come to <u>the party</u> tomorrow with <u>all of</u> his female <u>friends</u>.', 'is gone', 'the party', 'all of', 'friends', 'is gone'),
