(16, '2020-05-19 05:39:13', '2020-05-19 05:39:14', '3', 'That <u>handsome</u> man has <u>live</u> far <u>away from</u> his family <u>since 1990</u>.', 'handsome', 'live', 'away from', 'since', 'live'),
